SELECT o.branch AS branch, count() AS line_items, uniq(lp.order_hk) AS orders FROM rv.lnk_order_product AS lp INNER JOIN (SELECT order_hk, splitByString('__', record_source)[2] AS branch FROM rv.hub_order) AS o ON lp.order_hk = o.order_hk GROUP BY o.branch ORDER BY line_items DESC SETTINGS join_algorithm = 'partial_merge', max_bytes_before_external_group_by = 300000000, max_bytes_in_join = 300000000, max_memory_usage = 1800000000 FORMAT Null
